using System;
using System.Collections.Generic;
using System.Threading;

/// <summary>
/// Migrated from .NET Framework to .NET 8.
///
/// APIs removed and why:
///   - Thread.Abort()     → throws PlatformNotSupportedException in .NET 6+ (SYSLIB0006)
///   - Thread.Interrupt() → obsolete in .NET 9 (SYSLIB0046), unreliable even in Framework
///   - ManualResetEvent   → replaced with WaitHandle.WaitAny + CancellationToken.WaitHandle
///
/// Bugs fixed from the original:
///   1. Race condition: ManualResetEvent is not a counting semaphore. If multiple
///      Enqueue() calls happen before RunLoop wakes, only one item is dequeued —
///      the rest are silently lost. Fixed by draining all items per wake-up.
///   2. Empty-queue crash: _newEvent.Reset() between WaitOne and Dequeue means
///      another thread can observe the reset, enqueue+set, and the original thread
///      still dequeues only once — but if the queue was empty at the wrong moment,
///      it throws InvalidOperationException. Fixed by checking Count under lock.
/// </summary>
public class EventProcessor
{
    private readonly ManualResetEvent _newEvent = new ManualResetEvent(false);
    private readonly Queue<string> _queue = new Queue<string>();
    private readonly CancellationTokenSource _cts = new CancellationTokenSource();
    private Thread? _thread;
    private readonly object _lock = new object();

    public void Start()
    {
        _thread = new Thread(RunLoop);
        _thread.Start();
    }

    private void RunLoop()
    {
        var handles = new WaitHandle[] { _newEvent, _cts.Token.WaitHandle };

        while (!_cts.Token.IsCancellationRequested)
        {
            // Block until either a new event arrives or cancellation is requested.
            int signaled = WaitHandle.WaitAny(handles);

            // Index 1 = cancellation token was signaled → exit
            if (signaled == 1 || _cts.Token.IsCancellationRequested)
                break;

            // Drain all queued items (fixes the lost-event bug in the original)
            _newEvent.Reset();
            List<string> items;
            lock (_lock)
            {
                items = new List<string>(_queue);
                _queue.Clear();
            }

            foreach (var item in items)
            {
                if (_cts.Token.IsCancellationRequested)
                    break;
                Handle(item);
            }
        }
    }

    public void Enqueue(string item)
    {
        lock (_lock) { _queue.Enqueue(item); }
        _newEvent.Set();
    }

    public void Stop()
    {
        // Signal the cancellation token — this unblocks WaitHandle.WaitAny
        // and causes the loop to exit cooperatively.
        _cts.Cancel();

        // Wait for the thread to finish, with a timeout.
        _thread?.Join(5000);

        // Clean up resources.
        _cts.Dispose();
        _newEvent.Dispose();
    }

    private void Handle(string item)
    {
        // processing logic here
    }
}

